class Solution {
    public boolean canPartition(int[] nums) {
        int sum = 0;
        for (int num : nums) sum += num;
        if ((sum & 1) != 0) return false;
        int target = sum / 2;
        Boolean[][] memo = new Boolean[nums.length][target + 1];
        return dfs(nums, nums.length - 1, target, memo);
    }

    private boolean dfs(int[] nums, int i, int target, Boolean[][] memo) {
        if (target == 0) return true;
        if (i < 0 || target < 0) return false;
        if (memo[i][target] != null) return memo[i][target];
        boolean result = dfs(nums, i - 1, target - nums[i], memo) || dfs(nums, i - 1, target, memo);
        memo[i][target] = result;
        return result;
    }
}

class Solution {
    public boolean canPartition(int[] nums) {
        int sum = 0;
        for (int num : nums) sum += num;
        if ((sum & 1) != 0) return false;
        int target = sum / 2;
        boolean[] dp = new boolean[target + 1];
        dp[0] = true;
        for (int num : nums) {
            for (int j = target; j >= num; j--) {
                dp[j] = dp[j] || dp[j - num];
            }
        }
        return dp[target];
    }
}
